#!/bin/bash
set -e

echo "🔧 EAS pre-install: Installing provisioning profiles..."

PROFILE_DIR="$HOME/Library/MobileDevice/Provisioning Profiles"
mkdir -p "$PROFILE_DIR"

python3 << 'PYEOF'
import base64, os

profile_dir = os.path.join(os.path.expanduser('~'), 'Library', 'MobileDevice', 'Provisioning Profiles')
os.makedirs(profile_dir, exist_ok=True)

# Main app profile: SaintSalLabs AppStore (789S6DXFJK) - with Associated Domains
main_b64 = ""
main_out = os.path.join(profile_dir, 'saintsallabs.mobileprovision')
with open(main_out, 'wb') as f:
    f.write(base64.b64decode(main_b64))
print('✅ Main app profile installed:', main_out)

# App Clip profile: SaintSalLabs App Clip AppStore (WNCLLBZB7X)
clip_b64 = ""
clip_out = os.path.join(profile_dir, 'saintsallabsclip.mobileprovision')
with open(clip_out, 'wb') as f:
    f.write(base64.b64decode(clip_b64))
print('✅ App Clip profile installed:', clip_out)

PYEOF

echo "✅ Pre-install complete — both profiles installed"
